import{_ as e,c as r,o as t,ai as i}from"./chunks/framework.DApawI3z.js";const _=JSON.parse('{"title":"简介","description":"","frontmatter":{"title":"简介"},"headers":[],"relativePath":"docs/Introduction/index.md","filePath":"docs/Introduction/index.md"}'),n={name:"docs/Introduction/index.md"};function o(d,a,l,h,s,c){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to “简介”">​</a></h1><p><a href="https://github.com/ETS2LA" target="_blank" rel="noreferrer">ETS2LA</a>是一款开源免费的适用于欧卡2/美卡的辅助驾驶程序</p><p>ETS2LA 项目旨在最终将自动驾驶技术引入 SCS Software 的卡车模拟器 。本文档仍在编写中，并将随着项目进展进行更新。如有任何疑问，请在 Discord 中提问。</p><div class="tip custom-block"><p class="custom-block-title">来自于匿名用户</p><p>好吧，我不想在这个频道里疯狂分享我对这个程序的喜爱，因为我已经跟大家说过我有多喜欢它了，但我还是想再强调一遍：我坐轮椅，手部灵活性不够，无法自己玩这个游戏，完全是因为这个程序我才能玩！我真的非常喜欢它，也真心希望开发者们知道，我非常感谢他们为制作这个程序所付出的辛勤努力。因为我的残疾，我在现实世界中根本无法开车，而能够在模拟器里开车却能让我感到无比满足。🙂</p><p>匿名用户- ETS2LA Discord</p></div><h2 id="特征" tabindex="-1">特征 <a class="header-anchor" href="#特征" aria-label="Permalink to “特征”">​</a></h2><h2 id="完全访问模拟器数据" tabindex="-1">完全访问模拟器数据 <a class="header-anchor" href="#完全访问模拟器数据" aria-label="Permalink to “完全访问模拟器数据”">​</a></h2><p>与许多其他应用程序一样，我们使用 ETS2 目录中的遥测服务器来获取游戏中的实时数据。 然而，与其他应用程序不同的是， 我们可以访问游戏的道路和预制网络，从而构建真正的全自动驾驶体验，而无需计算成本高昂的视觉模型。现在，您无需加入多人游戏即可获得完美的电影级画面！</p><h2 id="多语言支持" tabindex="-1">多语言支持 <a class="header-anchor" href="#多语言支持" aria-label="Permalink to “多语言支持”">​</a></h2><p>我们提供了一个易于使用的翻译框架，可以将 ETS2LA 翻译成任何语言。任何人都可以使用，翻译状态完全由社区努力驱动！</p><h2 id="无缝导航" tabindex="-1">无缝导航 <a class="header-anchor" href="#无缝导航" aria-label="Permalink to “无缝导航”">​</a></h2><p>我们可以直接访问游戏内的导航路线。ETS2LA 会带您到达目的地，无论它位于何处。此功能适用于任何地图模组，只要提取了该模组或模组组合的道路数据即可。</p><h2 id="无需昂贵的-ai-模型" tabindex="-1">无需昂贵的 AI 模型 <a class="header-anchor" href="#无需昂贵的-ai-模型" aria-label="Permalink to “无需昂贵的 AI 模型”">​</a></h2><p>ETS2LA 完全由人工编写，完全不依赖人工智能。这意味着ETS2LA 比许多同类程序更加轻量级，性能也更高效。我们还深度实现了多处理功能，确保每个插件都有独立的 CPU 核心运行</p><h2 id="丰富的开发经验" tabindex="-1">丰富的开发经验 <a class="header-anchor" href="#丰富的开发经验" aria-label="Permalink to “丰富的开发经验”">​</a></h2><p>ETS2LA 包含一个易于使用的后端，任何人都可以为 ETS2LA 创建美观实用的插件。您只需几行 Python 代码即可定义完整的设置页面。我们还创建了一个强大的事件系统，让您可以监听游戏或应用程序中的任何事件或按键绑定。</p><h2 id="美观而现代的用户界面" tabindex="-1">美观而现代的用户界面 <a class="header-anchor" href="#美观而现代的用户界面" aria-label="Permalink to “美观而现代的用户界面”">​</a></h2><p>基于 NextJS 和 shadcn，我们制作了一个易于使用且美观的界面，该界面受到现实世界自动驾驶解决方案的启发。</p>',17)])])}const b=e(n,[["render",o]]);export{_ as __pageData,b as default};
